var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"상태는?","JPN":"具合はどう？","ENG":"How is she?","TWN":"情況如何？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"위험한 고비는 넘겼어.","JPN":"峠は越えたわ。","ENG":"The worst is over.","TWN":"已經渡過危險期。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"다행히 치명상은 피했는데......","JPN":"幸い、致命傷は免れたけど……","ENG":"Fortunately, it's not critical but...","TWN":"幸好她避開了致命傷，但是……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......피했는데?","JPN":"……免れたけど？","ENG":"But...?","TWN":"但是？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"그동안 충격이 많이 누적된 것 같아.","JPN":"これまでかなりのダメージが溜まっていたみたい。","ENG":"All the years of wounds and injuries might have caught up to her.","TWN":"她這段時間似乎受到了很多衝擊……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"의식을 회복하려면 시간이 좀 걸릴 수도 있겠어.","JPN":"意識を取り戻すには少し時間がかかるかもしれないわ。","ENG":"It may take some time for her to wake up.","TWN":"恢復意識可能要花點時間。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......생명에 지장이 없다니 스승님도 운이 좋군.","JPN":"……命に別条はないなんて、師匠もツイてるわね。","ENG":"At least her vitals are stable... Master got lucky.","TWN":"……竟然沒有生命危險，師父還真是幸運。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"고위 침식체의 공격에 직격당했다고 들었는데.","JPN":"高位侵食体の攻撃が直撃したというのに……","ENG":"I heard she took a direct hit from a high-level Corrupted Object.","TWN":"我聽說她是被高等侵蝕體的攻擊直接擊中的。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"카운터는 튼튼하니까.","JPN":"カウンターはタフだから。","ENG":"Well, Counters are sturdy like that.","TWN":"因為制裁者的身體很強壯啊。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"이런 점은 부럽네. 나도 조금만 더 건강했으면 좋았을 텐데.","JPN":"そういうところ、うらやましいわ。私ももう少し健康体なら良かったのに。","ENG":"I do envy that part about you guys. I wish I was a bit healthier.","TWN":"我真羡慕這一點，要是我也能稍微健康一點就好了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......너 스쿼시에 요가에 필라테스까지 하고 있잖아?","JPN":"……あなただって、スカッシュやヨガ、ピラティスまでこなしてるじゃない？","ENG":"But you're already doing squash, yoga, and pilates!","TWN":"……妳不是又在打壁球，又在做瑜伽還有普拉提斯嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"무슨 건강 타령이야?","JPN":"健康体そのものなのに。","ENG":"You're the last person to be complaining about health.","TWN":"這算哪門子的不健康啊？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"얘가 뭘 모르네.","JPN":"わかってないなー。","ENG":"You have no idea, do you?","TWN":"妳這孩子什麼都不懂呢。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"건강이란 건 항상 방심할 수 없는 거라고.","JPN":"健康というのはね、いつだって油断禁物よ。","ENG":"You can never let down your guard when it comes to health and fitness.","TWN":"健康這種東西，不論什麼時候都不能大意。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"특히나 나 같이 가녀린 지성인에겐 더더욱.","JPN":"とくに、私みたいな可憐な才女はね。","ENG":"Especially for frail intellectuals like myself.","TWN":"尤其像我這種纖細的知識分子，那就更是如此了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네, 네. 알았으니까 스승님을 부탁하지.","JPN":"はいはい、わかったから、師匠をお願いね。","ENG":"Sure, sure. Anyway, please take good care of her.","TWN":"是，是，那師父就拜託妳了。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......그래도 네가 따라가서 다행이야.","JPN":"……あなたがついてるなら、安心だわ。","ENG":"...I'm glad you went with them.","TWN":"……不管怎麼說，妳有跟著一起去真是太好了。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"들었지, 조교야?","JPN":"聞いた？助手。","ENG":"Did you hear that, Yoonjung?","TWN":"聽到了嗎，助教？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};